 1	import * as React from 'react';
 2	import { ToolbarFilter, InputGroup, TextInput, Button, ButtonVariant } from '@patternfly/react-core';
 3	import SearchIcon from '@patternfly/react-icons/dist/esm/icons/search-icon';
 4	import { FilterControlProps } from './FilterControl';
 5	import { SearchFilterCategory } from './FilterToolbar';
 6	
 7	export interface SearchFilterControlProps<TItem, TFilterCategoryKey extends string>
 8	  extends FilterControlProps<TItem, TFilterCategoryKey> {
 9	  category: SearchFilterCategory<TItem, TFilterCategoryKey>;
10	  isNumeric: boolean;
11	}
12	
13	export const SearchFilterControl = <TItem, TFilterCategoryKey extends string>({
14	  category,
15	  filterValue,
16	  setFilterValue,
17	  showToolbarItem,
18	  isNumeric,
19	  isDisabled = false,
20	  id
21	}: React.PropsWithChildren<SearchFilterControlProps<TItem, TFilterCategoryKey>>): JSX.Element | null => {
22	  // Keep internal copy of value until submitted by user
23	  const [inputValue, setInputValue] = React.useState(filterValue?.[0] || '');
24	  // Update it if it changes externally
25	  React.useEffect(() => {
26	    setInputValue(filterValue?.[0] || '');
27	  }, [filterValue]);
28	
29	  const onFilterSubmit = () =>
30	    // Ignore value with multiple spaces
31	    setFilterValue(inputValue ? [inputValue.replace(/\s+/g, ' ')] : []);
32	
33	  const inputId = `${id}-${category.key}-input`;
34	  return (
35	    <ToolbarFilter
36	      labels={filterValue || []}
37	      deleteLabel={() => setFilterValue([])}
38	      categoryName={category.title}
39	      showToolbarItem={showToolbarItem}
40	    >
41	      <InputGroup role="group">
42	        <TextInput
43	          name={inputId}
44	          id={inputId}
45	          type={isNumeric ? 'number' : 'search'}
46	          onChange={(_, value) => setInputValue(value)}
47	          aria-label={`${category.title} filter`}
48	          value={inputValue}
49	          placeholder={category.placeholderText}
50	          onKeyDown={(event: React.KeyboardEvent) => {
51	            if (event.key && event.key !== 'Enter') {
52	              return;
53	            }
54	            onFilterSubmit();
55	          }}
56	          isDisabled={isDisabled}
57	        />
58	        <Button
59	          variant={ButtonVariant.control}
60	          id={`${id}-search-button`}
61	          aria-label="search button for search input"
62	          onClick={onFilterSubmit}
63	          isDisabled={isDisabled}
64	        >
65	          <SearchIcon />
66	        </Button>
67	      </InputGroup>
68	    </ToolbarFilter>
69	  );
70	};

